import{_ as a,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Introducing Advanced Compliance","description":"","frontmatter":{"title":"Introducing Advanced Compliance","slug":"introducing-advanced-compliance"},"headers":[],"relativePath":"account-hub/introducing-advanced-compliance.md","filePath":"account-hub/introducing-advanced-compliance.md"}'),c={name:"account-hub/introducing-advanced-compliance.md"};function o(r,e,d,s,l,u){return t(),n("div",null,[...e[0]||(e[0]=[i('<p>Branch is bringing in a new level of support to customers with our Advanced Compliance offering! Get the latest information here 💗</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Advanced Compliance is a <strong>premium</strong> solution from Branch that offers enhanced privacy and data security measures, enabling customers in highly regulated industries to use Branch&#39;s linking and measurement services while helping them to fulfill their heightened compliance requirements. Some of the advanced security configuration features include:</p><ul><li>Advanced Security Gateway - A gated data architecture, that includes an isolated network with custom traffic routing, more robust authentication, and additional levels of encryption.</li><li>Protected API - Data will flow through a gated and segregated environment, in which access to customer data is restricted based on business needs.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ready to learn more about Advanced Compliance like enabling it? View our guide here: <a href="./advanced-compliance.html">Advanced Compliance</a></p><p>Additionally, we&#39;ve updated our <a href="./best-practices-to-minimize-data-sent-to-branch.html">Best Practices to Minimize Data Sent to Branch guide</a>.</p></div>',5)])])}const h=a(c,[["render",o]]);export{p as __pageData,h as default};
